147â†’    private fun observeDiscoverFeed() {
148â†’        // listen to changes to the discover feed
149â†’        _uiState.addSource(readerDiscoverDataProvider.discoverFeed) { posts ->
150â†’            launch {
151â†’                val userTags = getFollowedTagsUseCase.get()
152â†’                if (userTags.isEmpty()) {
153â†’                    _uiState.value = DiscoverUiState.EmptyUiState.ShowNoFollowedTagsUiState {
154â†’                        parentViewModel.onShowReaderInterests()
155â†’                    }
156â†’                } else {
157â†’                    if (posts != null && posts.cards.isNotEmpty()) {
158â†’                        _uiState.value = DiscoverUiState.ContentUiState(
159â†’                            convertCardsToUiStates(posts),
160â†’                            reloadProgressVisibility = false,
161â†’                            loadMoreProgressVisibility = false,
162â†’                        )
163â†’                        if (swipeToRefreshTriggered) {
164â†’                            _scrollToTopEvent.postValue(Event(Unit))
165â†’                            swipeToRefreshTriggered = false
166â†’                        }
167â†’                    } else {
168â†’                        _uiState.value = DiscoverUiState.EmptyUiState.ShowNoPostsUiState {
169â†’                            _navigationEvents.value = Event(ShowReaderSubs)
170â†’                        }
171â†’                    }
172â†’                }
173â†’            }
174â†’        }
175â†’    }
