177â†’    private fun observeFollowStatus() {
178â†’        // listen to changes on follow status for updating the reader recommended blogs state immediately
179â†’        _uiState.addSource(readerPostCardActionsHandler.followStatusUpdated) { data ->
180â†’            val currentUiState: DiscoverUiState.ContentUiState = _uiState.value as? DiscoverUiState.ContentUiState
181â†’                ?: return@addSource
182â†’            val mutableCards = currentUiState.cards.toMutableList()
183â†’            var hasChangedCards = false
184â†’
185â†’            for (i in mutableCards.indices) {
186â†’                val card = mutableCards[i] as? ReaderCardUiState.ReaderRecommendedBlogsCardUiState ?: continue
187â†’                val mutableBlogs = card.blogs.toMutableList()
188â†’                var hasChangedBlogs = false
189â†’
190â†’                for (j in mutableBlogs.indices) {
191â†’                    val blog = mutableBlogs[j]
192â†’                    if (blog.blogId == data.blogId && blog.feedId == data.feedId) {
193â†’                        mutableBlogs[j] = blog.copy(isFollowed = data.following, isFollowEnabled = data.isChangeFinal)
194â†’                        hasChangedBlogs = true
195â†’                    }
196â†’                }
197â†’
198â†’                if (hasChangedBlogs) {
199â†’                    mutableCards[i] = card.copy(blogs = mutableBlogs)
200â†’                    hasChangedCards = true
201â†’                }
202â†’            }
203â†’
204â†’            if (hasChangedCards) {
205â†’                _uiState.value = currentUiState.copy(cards = mutableCards)
206â†’            }
207â†’        }
208â†’    }
