{"file_path": "/project/WordPress/src/test/java/org/wordpress/android/ui/reader/discover/ReaderDiscoverOnboardingTest.kt", "content": "package org.wordpress.android.ui.reader.discover

import androidx.lifecycle.MutableLiveData
import kotlinx.coroutines.ExperimentalCoroutinesApi
import org.assertj.core.api.Assertions.assertThat
import org.junit.Before
import org.junit.Test
import org.junit.runner.RunWith
import org.mockito.Mock
import org.mockito.junit.MockitoJUnitRunner
import org.mockito.kotlin.any
import org.mockito.kotlin.anyOrNull
import org.mockito.kotlin.mock
import org.mockito.kotlin.whenever
import org.wordpress.android.BaseUnitTest
import org.wordpress.android.models.ReaderTag
import org.wordpress.android.models.ReaderTagList
import org.wordpress.android.models.ReaderTagType
import org.wordpress.android.models.discover.ReaderDiscoverCards
import org.wordpress.android.ui.pages.SnackbarMessageHolder
import org.wordpress.android.ui.reader.discover.ReaderDiscoverViewModel.DiscoverUiState.EmptyUiState.ShowNoFollowedTagsUiState
import org.wordpress.android.ui.reader.reblog.ReblogUseCase
import org.wordpress.android.ui.reader.repository.ReaderDiscoverCommunication
import org.wordpress.android.ui.reader.repository.ReaderDiscoverDataProvider
import org.wordpress.android.ui.reader.repository.usecases.tags.GetFollowedTagsUseCase
import org.wordpress.android.ui.reader.tracker.ReaderTracker
import org.wordpress.android.ui.reader.usecases.BookmarkPostState.PreLoadPostContent
import org.wordpress.android.ui.reader.utils.ReaderUtilsWrapper
import org.wordpress.android.ui.reader.viewmodels.ReaderViewModel
import org.wordpress.android.util.DisplayUtilsWrapper
import org.wordpress.android.util.config.ReaderImprovementsFeatureConfig
import org.wordpress.android.viewmodel.Event
import org.wordpress.android.viewmodel.ReactiveMutableLiveData

/**
 * Test cases for Reader Discover onboarding functionality with dailyprompt tag handling
 */
@ExperimentalCoroutinesApi
@RunWith(MockitoJUnitRunner::class)
class ReaderDiscoverOnboardingTest : BaseUnitTest() {
    @Mock
    private lateinit var readerDiscoverDataProvider: ReaderDiscoverDataProvider

    @Mock
    private lateinit var uiStateBuilder: ReaderPostUiStateBuilder

    @Mock
    private lateinit var menuUiStateBuilder: ReaderPostMoreButtonUiStateBuilder

    @Mock
    private lateinit var readerPostCardActionsHandler: ReaderPostCardActionsHandler

    @Mock
    private lateinit var reblogUseCase: ReblogUseCase

    @Mock
    private lateinit var readerUtilsWrapper: ReaderUtilsWrapper

    @Mock
    private lateinit var getFollowedTagsUseCase: GetFollowedTagsUseCase

    @Mock
    private lateinit var readerTracker: ReaderTracker

    @Mock
    private lateinit var displayUtilsWrapper: DisplayUtilsWrapper

    @Mock
    private lateinit var parentViewModel: ReaderViewModel

    @Mock
    private lateinit var readerImprovementsFeatureConfig: ReaderImprovementsFeatureConfig

    private val fakeDiscoverFeed = ReactiveMutableLiveData<ReaderDiscoverCards>()
    private val fakeCommunicationChannel = MutableLiveData<Event<ReaderDiscoverCommunication>>()
    private val fakeNavigationFeed = MutableLiveData<Event<ReaderNavigationEvents>>()
    private val fakeSnackBarFeed = MutableLiveData<Event<SnackbarMessageHolder>>()
    private val fakePreloadPostFeed = MutableLiveData<Event<PreLoadPostContent>>()
    private val fakeFollowStatusChangedFeed = MutableLiveData<org.wordpress.android.ui.reader.usecases.ReaderSiteFollowUseCase.FollowSiteState.FollowStatusChanged>()

    private lateinit var viewModel: ReaderDiscoverViewModel

    @Before
    fun setUp() = test {
        viewModel = ReaderDiscoverViewModel(
            uiStateBuilder,
            menuUiStateBuilder,
            readerPostCardActionsHandler,
            readerDiscoverDataProvider,
            reblogUseCase,
            readerUtilsWrapper,
            readerTracker,
            displayUtilsWrapper,
            getFollowedTagsUseCase,
            readerImprovementsFeatureConfig,
            testDispatcher(),
            testDispatcher()
        )
        whenever(readerDiscoverDataProvider.discoverFeed).thenReturn(fakeDiscoverFeed)
        whenever(readerPostCardActionsHandler.navigationEvents).thenReturn(fakeNavigationFeed)
        whenever(readerPostCardActionsHandler.snackbarEvents).thenReturn(fakeSnackBarFeed)
        whenever(readerPostCardActionsHandler.preloadPostEvents).thenReturn(fakePreloadPostFeed)
        whenever(readerPostCardActionsHandler.followStatusUpdated).thenReturn(fakeFollowStatusChangedFeed)
        whenever(readerUtilsWrapper.getTagFromTagName(anyOrNull(), anyOrNull())).thenReturn(mock())
        whenever(menuUiStateBuilder.buildMoreMenuItems(anyOrNull(), any(), anyOrNull())).thenReturn(mock())
        whenever(readerDiscoverDataProvider.communicationChannel).thenReturn(fakeCommunicationChannel)
        whenever(readerImprovementsFeatureConfig.isEnabled()).thenReturn(false)
    }

    @Test
    fun `onboarding shown when user has only dailyprompt tag`() = test {
        // Arrange
        val dailyPromptTag = createReaderTag("dailyprompt")
        val userTags = ReaderTagList().apply { add(dailyPromptTag) }
        whenever(getFollowedTagsUseCase.get()).thenReturn(userTags)

        val uiStates = mutableListOf<ReaderDiscoverViewModel.DiscoverUiState>()
        viewModel.uiState.observeForever { uiStates.add(it) }

        // Act
        viewModel.start(parentViewModel)
        fakeDiscoverFeed.value = ReaderDiscoverCards(emptyList())

        // Assert
        assertThat(uiStates.last()).isInstanceOf(ShowNoFollowedTagsUiState::class.java)
    }

    @Test
    fun `onboarding shown when user has only dailyprompt-123 tag`() = test {
        // Arrange
        val dailyPromptIdTag = createReaderTag("dailyprompt-123")
        val userTags = ReaderTagList().apply { add(dailyPromptIdTag) }
        whenever(getFollowedTagsUseCase.get()).thenReturn(userTags)

        val uiStates = mutableListOf<ReaderDiscoverViewModel.DiscoverUiState>()
        viewModel.uiState.observeForever { uiStates.add(it) }

        // Act
        viewModel.start(parentViewModel)
        fakeDiscoverFeed.value = ReaderDiscoverCards(emptyList())

        // Assert
        assertThat(uiStates.last()).isInstanceOf(ShowNoFollowedTagsUiState::class.java)
    }

    @Test
    fun `onboarding shown when user has multiple dailyprompt tags`() = test {
        // Arrange
        val dailyPromptTag1 = createReaderTag("dailyprompt")
        val dailyPromptTag2 = createReaderTag("dailyprompt-123")
        val dailyPromptTag3 = createReaderTag("dailyprompt-456")
        val userTags = ReaderTagList().apply {
            add(dailyPromptTag1)
            add(dailyPromptTag2)
            add(dailyPromptTag3)
        }
        whenever(getFollowedTagsUseCase.get()).thenReturn(userTags)

        val uiStates = mutableListOf<ReaderDiscoverViewModel.DiscoverUiState>()
        viewModel.uiState.observeForever { uiStates.add(it) }

        // Act
        viewModel.start(parentViewModel)
        fakeDiscoverFeed.value = ReaderDiscoverCards(emptyList())

        // Assert
        assertThat(uiStates.last()).isInstanceOf(ShowNoFollowedTagsUiState::class.java)
    }

    @Test
    fun `onboarding NOT shown when user has dailyprompt plus other tags`() = test {
        // Arrange
        val dailyPromptTag = createReaderTag("dailyprompt")
        val regularTag = createReaderTag("technology")
        val userTags = ReaderTagList().apply {
            add(dailyPromptTag)
            add(regularTag)
        }
        whenever(getFollowedTagsUseCase.get()).thenReturn(userTags)

        val uiStates = mutableListOf<ReaderDiscoverViewModel.DiscoverUiState>()
        viewModel.uiState.observeForever { uiStates.add(it) }

        // Act
        viewModel.start(parentViewModel)
        fakeDiscoverFeed.value = ReaderDiscoverCards(emptyList())

        // Assert - Should show "no posts" UI state, not the onboarding
        assertThat(uiStates.last()).isNotInstanceOf(ShowNoFollowedTagsUiState::class.java)
    }

    @Test
    fun `onboarding shown when user has no tags at all`() = test {
        // Arrange
        val userTags = ReaderTagList()
        whenever(getFollowedTagsUseCase.get()).thenReturn(userTags)

        val uiStates = mutableListOf<ReaderDiscoverViewModel.DiscoverUiState>()
        viewModel.uiState.observeForever { uiStates.add(it) }

        // Act
        viewModel.start(parentViewModel)
        fakeDiscoverFeed.value = ReaderDiscoverCards(emptyList())

        // Assert
        assertThat(uiStates.last()).isInstanceOf(ShowNoFollowedTagsUiState::class.java)
    }

    private fun createReaderTag(slug: String): ReaderTag {
        return ReaderTag(
            slug,
            slug,
            slug,
            "/read/tags/$slug/posts",
            ReaderTagType.FOLLOWED
        )
    }
}
