    fun setUp() {
        viewModel = ReaderInterestsViewModel(
            readerTagRepository,
            readerTracker
        )
    }

    @Test
    fun `interests screen shown when user has only dailyprompt tag from Discover entry point`() = test {
        // Arrange
        val dailyPromptTag = createReaderTag("dailyprompt")
        val userTags = ReaderTagList().apply { add(dailyPromptTag) }
        val interestsTags = createInterestTags()

        whenever(readerTagRepository.getUserTags()).thenReturn(
            ReaderRepositoryCommunication.SuccessWithData(userTags)
        )
        whenever(readerTagRepository.getInterests()).thenReturn(
            ReaderRepositoryCommunication.SuccessWithData(interestsTags)
        )

        val uiStates = mutableListOf<ReaderInterestsViewModel.UiState>()
        viewModel.uiState.observeForever { uiStates.add(it) }

        // Act
        viewModel.start("en", parentViewModel, EntryPoint.DISCOVER)

        // Assert - Should show interests content, not close immediately
        assertThat(uiStates.last()).isInstanceOf(ContentUiState::class.java)
    }

    @Test
    fun `interests screen shown when user has only dailyprompt-123 tag from Discover entry point`() = test {
        // Arrange
        val dailyPromptIdTag = createReaderTag("dailyprompt-123")
        val userTags = ReaderTagList().apply { add(dailyPromptIdTag) }
        val interestsTags = createInterestTags()

        whenever(readerTagRepository.getUserTags()).thenReturn(
            ReaderRepositoryCommunication.SuccessWithData(userTags)
