@ExperimentalCoroutinesApi
@RunWith(MockitoJUnitRunner::class)
class ReaderInterestsOnboardingTest : BaseUnitTest() {
    @Mock
    private lateinit var readerTagRepository: ReaderTagRepository

    @Mock
    private lateinit var readerTracker: ReaderTracker

    @Mock
    private lateinit var parentViewModel: ReaderViewModel

    private lateinit var viewModel: ReaderInterestsViewModel

    @Before
    fun setUp() {
        viewModel = ReaderInterestsViewModel(
            readerTagRepository,
            readerTracker
        )
    }

    @Test
    fun `interests screen shown when user has only dailyprompt tag from Discover entry point`() = test {
        // Arrange
        val dailyPromptTag = createReaderTag("dailyprompt")
        val userTags = ReaderTagList().apply { add(dailyPromptTag) }
        val interestsTags = createInterestTags()

        whenever(readerTagRepository.getUserTags()).thenReturn(
            ReaderRepositoryCommunication.SuccessWithData(userTags)
        )
        whenever(readerTagRepository.getInterests()).thenReturn(
            ReaderRepositoryCommunication.SuccessWithData(interestsTags)
        )

        val uiStates = mutableListOf<ReaderInterestsViewModel.UiState>()
        viewModel.uiState.observeForever { uiStates.add(it) }

        // Act
        viewModel.start("en", parentViewModel, EntryPoint.DISCOVER)

        // Assert - Should show interests content, not close immediately
        assertThat(uiStates.last()).isInstanceOf(ContentUiState::class.java)
    }

    @Test
    fun `interests screen shown when user has only dailyprompt-123 tag from Discover entry point`() = test {
        // Arrange
        val dailyPromptIdTag = createReaderTag("dailyprompt-123")
        val userTags = ReaderTagList().apply { add(dailyPromptIdTag) }
        val interestsTags = createInterestTags()

        whenever(readerTagRepository.getUserTags()).thenReturn(
            ReaderRepositoryCommunication.SuccessWithData(userTags)
        )
        whenever(readerTagRepository.getInterests()).thenReturn(
            ReaderRepositoryCommunication.SuccessWithData(interestsTags)
        )

        val uiStates = mutableListOf<ReaderInterestsViewModel.UiState>()
        viewModel.uiState.observeForever { uiStates.add(it) }

        // Act
        viewModel.start("en", parentViewModel, EntryPoint.DISCOVER)

        // Assert - Should show interests content, not close immediately
        assertThat(uiStates.last()).isInstanceOf(ContentUiState::class.java)
    }

    @Test
    fun `interests screen shown when user has multiple dailyprompt tags from Discover entry point`() = test {
        // Arrange
        val dailyPromptTag1 = createReaderTag("dailyprompt")
        val dailyPromptTag2 = createReaderTag("dailyprompt-123")
        val dailyPromptTag3 = createReaderTag("dailyprompt-456")
        val userTags = ReaderTagList().apply {
            add(dailyPromptTag1)
            add(dailyPromptTag2)
            add(dailyPromptTag3)
        }
        val interestsTags = createInterestTags()

        whenever(readerTagRepository.getUserTags()).thenReturn(
            ReaderRepositoryCommunication.SuccessWithData(userTags)
        )
        whenever(readerTagRepository.getInterests()).thenReturn(
            ReaderRepositoryCommunication.SuccessWithData(interestsTags)
        )

        val uiStates = mutableListOf<ReaderInterestsViewModel.UiState>()
        viewModel.uiState.observeForever { uiStates.add(it) }

        // Act
        viewModel.start("en", parentViewModel, EntryPoint.DISCOVER)

        // Assert - Should show interests content, not close immediately
        assertThat(uiStates.last()).isInstanceOf(ContentUiState::class.java)
    }

    @Test
    fun `interests screen NOT shown when user has dailyprompt plus other tags from Discover entry point`() = test {
        // Arrange
        val dailyPromptTag = createReaderTag("dailyprompt")
        val regularTag = createReaderTag("technology")
        val userTags = ReaderTagList().apply {
            add(dailyPromptTag)
            add(regularTag)
        }

        whenever(readerTagRepository.getUserTags()).thenReturn(
            ReaderRepositoryCommunication.SuccessWithData(userTags)
        )

        // Act
        viewModel.start("en", parentViewModel, EntryPoint.DISCOVER)

        // Assert - Should close immediately, not show interests
        verify(parentViewModel).onCloseReaderInterests()
    }

    @Test
    fun `interests screen shown when user has no tags from Discover entry point`() = test {
        // Arrange
        val userTags = ReaderTagList()
        val interestsTags = createInterestTags()

        whenever(readerTagRepository.getUserTags()).thenReturn(
            ReaderRepositoryCommunication.SuccessWithData(userTags)
        )
        whenever(readerTagRepository.getInterests()).thenReturn(
            ReaderRepositoryCommunication.SuccessWithData(interestsTags)
        )

        val uiStates = mutableListOf<ReaderInterestsViewModel.UiState>()
        viewModel.uiState.observeForever { uiStates.add(it) }

        // Act
        viewModel.start("en", parentViewModel, EntryPoint.DISCOVER)

        // Assert - Should show interests content
        assertThat(uiStates.last()).isInstanceOf(ContentUiState::class.java)
    }

    @Test
    fun `interests always shown from Settings entry point regardless of dailyprompt tags`() = test {
        // Arrange
        val dailyPromptTag = createReaderTag("dailyprompt")
        val regularTag = createReaderTag("technology")
        val userTags = ReaderTagList().apply {
            add(dailyPromptTag)
            add(regularTag)
        }
        val interestsTags = createInterestTags()

        whenever(readerTagRepository.getUserTags()).thenReturn(
            ReaderRepositoryCommunication.SuccessWithData(userTags)
        )
        whenever(readerTagRepository.getInterests()).thenReturn(
            ReaderRepositoryCommunication.SuccessWithData(interestsTags)
        )

        val uiStates = mutableListOf<ReaderInterestsViewModel.UiState>()
        viewModel.uiState.observeForever { uiStates.add(it) }

        // Act
        viewModel.start("en", null, EntryPoint.SETTINGS)

        // Assert - Should always show interests content from settings
        assertThat(uiStates.last()).isInstanceOf(ContentUiState::class.java)
    }

    private fun createReaderTag(slug: String): ReaderTag {
        return ReaderTag(
            slug,
            slug,
            slug,
            "/read/tags/$slug/posts",
            ReaderTagType.FOLLOWED
        )
    }

    private fun createInterestTags(): ReaderTagList {
        return ReaderTagList().apply {
            add(createReaderTag("technology"))
            add(createReaderTag("design"))
            add(createReaderTag("photography"))
        }
    }
}
